module quick_sort(input [15:0] data_in, output reg [15:0] data_out);  
    reg [7:0] obf_arr [1:0];  
    integer i, j;  
    always @(*) begin  
        obf_arr[0] = data_in[15:8];  
        obf_arr[1] = data_in[7:0];  

        // Simple Bubble Sort for 2 elements  
        for (i = 0; i < 1; i = i + 1) begin  
            for (j = 0; j < 1 - i; j = j + 1) begin  
                if (obf_arr[j] > obf_arr[j + 1]) begin  
                    // Swap  
                    {obf_arr[j], obf_arr[j + 1]} = {obf_arr[j + 1], obf_arr[j]};  
                end  
            end  
        end  

        data_out = {obf_arr[0], obf_arr[1]};  
    end  
endmodule
